class Solution {
public:
    int countCharacters(vector<string>& words, string chars) {
        int count_chars[26] = {0};
        for (char c : chars) {
            count_chars[c - 'a']++;
        }

        int result = 0;

        for (string word : words) {
            int count_word[26] = {0};
            for (char c : word) {
                count_word[c - 'a']++;
            }

            bool isGood = true;
            for (int i = 0; i < 26; i++) {
                if (count_word[i] > count_chars[i]) {
                    isGood = false;
                    break;
                }
            }

            if (isGood) {
                result += word.length();
            }
        }

        return result;
    }
};

